1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const DEFAULT_BASE_PREMIUM = 100;
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	function basePremiumFor(item: Item): number {
26	  return BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
27	}
28	
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	
32	function groupByType(items: Item[]): Map<string, Item[]> {
33	  const groups = new Map<string, Item[]>();
34	  for (const item of items) {
35	    const group = groups.get(item.type) ?? [];
36	    group.push(item);
37	    groups.set(item.type, group);
38	  }
39	  return groups;
40	}
41	
42	function basePremiumForGroup(group: Item[]): number {
43	  if (group.length === BLOCK_SIZE) {
44	    return BLOCK_PREMIUM;
45	  }
46	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
47	}
48	
49	export function quote(input: QuoteInput): QuoteResult {
50	  let basePremium = 0;
51	  for (const group of groupByType(input.items).values()) {
52	    basePremium += basePremiumForGroup(group);
53	  }
54	
55	  return { premium: basePremium + PROCESSING_FEE };
56	}
